// ===============================
// INPUT VARIABLES
// ===============================

// Канонические режимы:
// "realistic_modern"
// "realistic_documentary"
// "illustrated_2d"
const VISUAL_MODE = $('get all workflow params').first().json.videoVisualMode;

// Глобальные входы
const SELECTED_CLUSTER_PLAN = $('get selectedClusterPlan').first().json;
const VISUAL_NARRATION_STRATEGY = $('get visualNarrationStrategy').first().json;
const GLOBAL_VISUAL_POLICY = $('get all workflow params').first().json.visualTextLanguagePolicy;

// ===============================
// HELPERS
// ===============================

function safeString(value, fallback = "") {
  return typeof value === "string" ? value : fallback;
}

function safeBool(value, fallback = false) {
  return typeof value === "boolean" ? value : fallback;
}

function normalizeVisualMode(modeRaw) {
  const mode = safeString(modeRaw).trim();

  // legacy aliases
  if (mode === "realistic_live_action") return "realistic_modern";
  if (mode === "realistic_archival") return "realistic_documentary";
  if (mode === "documentary") return "realistic_documentary";
  if (mode === "2d" || mode === "illustrated2d") return "illustrated_2d";

  if (
    mode === "realistic_modern" ||
    mode === "realistic_documentary" ||
    mode === "illustrated_2d"
  ) {
    return mode;
  }

  return "";
}

function deriveVisualMode(explicitMode, itemJson, rawInput) {
  const candidates = [
    explicitMode,
    itemJson.visual_mode,
    itemJson.visualMode,
    rawInput.visual_mode,
    rawInput.visualMode,
  ];

  for (const candidate of candidates) {
    const normalized = normalizeVisualMode(candidate);
    if (normalized) return normalized;
  }

  return "realistic_modern";
}

function getPromptFamily(visualMode, selectedBaseFormat) {
  switch (selectedBaseFormat) {
    case "observational_video":
      return visualMode === "illustrated_2d"
        ? "illustrated_scene_i2v"
        : "realistic_scene_i2v";

    case "archival_material":
      return visualMode === "illustrated_2d"
        ? "illustrated_scene_i2v"
        : "archival_realistic_scene";

    case "explanatory_graphic":
      return "technical_diagram";

    case "spatial_map":
      return "spatial_map_graphic";

    case "ui_data_visual":
      return "ui_data_visual_graphic";

    case "still_image":
      return visualMode === "illustrated_2d"
        ? "illustrated_still_image"
        : "realistic_still_image";

    case "text_only_card":
      return "text_only_card_graphic";

    default:
      return "unknown";
  }
}

function getTemplateIds(promptFamily, visualMode, useExplanatoryLayer) {
  switch (promptFamily) {
    case "realistic_scene_i2v":
      if (visualMode === "realistic_documentary") {
        return {
          base_visuals_requirements_id: "realistic_documentary_base_requirements_v1",
          starting_frame_template_id: "realistic_documentary_start_frame_v1",
          clip_template_id: "realistic_documentary_clip_v1",
          overlay_template_id: useExplanatoryLayer ? "scene_overlay_v1" : null,
        };
      }

      return {
        base_visuals_requirements_id: "realistic_modern_base_requirements_v1",
        starting_frame_template_id: "realistic_modern_start_frame_v1",
        clip_template_id: "realistic_modern_clip_v1",
        overlay_template_id: useExplanatoryLayer ? "scene_overlay_v1" : null,
      };

    case "archival_realistic_scene":
      return {
        base_visuals_requirements_id: "realistic_documentary_base_requirements_v1",
        starting_frame_template_id: "realistic_documentary_start_frame_v1",
        clip_template_id: "realistic_documentary_clip_v1",
        overlay_template_id: useExplanatoryLayer ? "scene_overlay_v1" : null,
      };

    case "illustrated_scene_i2v":
      return {
        base_visuals_requirements_id: "illustrated_2d_base_requirements_v1",
        starting_frame_template_id: "illustrated_2d_start_frame_v1",
        clip_template_id: "illustrated_2d_clip_v1",
        overlay_template_id: useExplanatoryLayer ? "graphic_overlay_v1" : null,
      };

    case "technical_diagram":
      return {
        base_visuals_requirements_id: "technical_diagram_base_requirements_v1",
        starting_frame_template_id: "technical_diagram_start_frame_v1",
        clip_template_id: "technical_diagram_clip_v1",
        overlay_template_id: useExplanatoryLayer ? "technical_diagram_overlay_v1" : null,
      };

    case "spatial_map_graphic":
      return {
        base_visuals_requirements_id: "spatial_map_base_requirements_v1",
        starting_frame_template_id: "spatial_map_start_frame_v1",
        clip_template_id: "spatial_map_clip_v1",
        overlay_template_id: useExplanatoryLayer ? "spatial_map_overlay_v1" : null,
      };

    case "ui_data_visual_graphic":
      return {
        base_visuals_requirements_id: "ui_data_visual_base_requirements_v1",
        starting_frame_template_id: "ui_data_visual_start_frame_v1",
        clip_template_id: "ui_data_visual_clip_v1",
        overlay_template_id: useExplanatoryLayer ? "ui_data_visual_overlay_v1" : null,
      };

    case "realistic_still_image":
      return {
        base_visuals_requirements_id:
          visualMode === "realistic_documentary"
            ? "realistic_documentary_base_requirements_v1"
            : "realistic_modern_base_requirements_v1",
        starting_frame_template_id:
          visualMode === "realistic_documentary"
            ? "realistic_documentary_still_start_frame_v1"
            : "realistic_modern_still_start_frame_v1",
        clip_template_id: null,
        overlay_template_id: useExplanatoryLayer ? "scene_overlay_v1" : null,
      };

    case "illustrated_still_image":
      return {
        base_visuals_requirements_id: "illustrated_2d_base_requirements_v1",
        starting_frame_template_id: "illustrated_2d_still_start_frame_v1",
        clip_template_id: null,
        overlay_template_id: useExplanatoryLayer ? "graphic_overlay_v1" : null,
      };

    case "text_only_card_graphic":
      return {
        base_visuals_requirements_id: "text_card_base_requirements_v1",
        starting_frame_template_id: "text_card_start_frame_v1",
        clip_template_id: null,
        overlay_template_id: null,
      };

    default:
      return {
        base_visuals_requirements_id: null,
        starting_frame_template_id: null,
        clip_template_id: null,
        overlay_template_id: null,
      };
  }
}

function getLanguagePolicy(promptFamily) {
  switch (promptFamily) {
    case "realistic_scene_i2v":
    case "archival_realistic_scene":
    case "realistic_still_image":
      return {
        camera_language_allowed: true,
        photo_technical_language_allowed: true,
        film_grain_allowed: true,
        lens_language_allowed: true,
        sensor_language_allowed: true,
        handheld_language_allowed: true,
        style_keywords_allowed: false,
        lora_style_external: true,
      };

    case "illustrated_scene_i2v":
    case "technical_diagram":
    case "spatial_map_graphic":
    case "ui_data_visual_graphic":
    case "illustrated_still_image":
    case "text_only_card_graphic":
      return {
        camera_language_allowed: false,
        photo_technical_language_allowed: false,
        film_grain_allowed: false,
        lens_language_allowed: false,
        sensor_language_allowed: false,
        handheld_language_allowed: false,
        style_keywords_allowed: false,
        lora_style_external: true,
      };

    default:
      return {
        camera_language_allowed: false,
        photo_technical_language_allowed: false,
        film_grain_allowed: false,
        lens_language_allowed: false,
        sensor_language_allowed: false,
        handheld_language_allowed: false,
        style_keywords_allowed: false,
        lora_style_external: true,
      };
  }
}

function buildAllowedPromptElements(languagePolicy) {
  const out = [];
  if (languagePolicy.camera_language_allowed) out.push("camera_language");
  if (languagePolicy.photo_technical_language_allowed) out.push("photo_technical_language");
  if (languagePolicy.film_grain_allowed) out.push("film_grain");
  if (languagePolicy.lens_language_allowed) out.push("lens_language");
  if (languagePolicy.sensor_language_allowed) out.push("sensor_language");
  if (languagePolicy.handheld_language_allowed) out.push("handheld_language");
  return out;
}

function buildForbiddenPromptElements(languagePolicy) {
  const out = [];
  if (!languagePolicy.camera_language_allowed) out.push("camera_language");
  if (!languagePolicy.photo_technical_language_allowed) out.push("photo_technical_language");
  if (!languagePolicy.film_grain_allowed) out.push("film_grain");
  if (!languagePolicy.lens_language_allowed) out.push("lens_language");
  if (!languagePolicy.sensor_language_allowed) out.push("sensor_language");
  if (!languagePolicy.handheld_language_allowed) out.push("handheld_language");
  if (!languagePolicy.style_keywords_allowed) out.push("style_keywords");
  return out;
}

function getPromptFamilyKind(promptFamily) {
  if (
    promptFamily === "realistic_scene_i2v" ||
    promptFamily === "archival_realistic_scene" ||
    promptFamily === "illustrated_scene_i2v"
  ) {
    return "scene_based";
  }

  if (
    promptFamily === "technical_diagram" ||
    promptFamily === "spatial_map_graphic" ||
    promptFamily === "ui_data_visual_graphic"
  ) {
    return "graphic_based";
  }

  if (
    promptFamily === "realistic_still_image" ||
    promptFamily === "illustrated_still_image"
  ) {
    return "still_based";
  }

  if (promptFamily === "text_only_card_graphic") {
    return "text_card_based";
  }

  return "unknown";
}

function getStartFrameTextMode(promptFamilyKind, selectedBaseFormat) {
  if (selectedBaseFormat === "text_only_card") return "required";
  if (promptFamilyKind === "graphic_based") return "required";
  return "forbid";
}

function buildWarnings(
  selectedBaseFormat,
  promptFamily,
  visualModeRaw,
  visualModeNormalized
) {
  const warnings = [];

  if (selectedBaseFormat === "text_only_card") {
    warnings.push("selected_base_format_is_text_only_card");
  }

  if (promptFamily === "unknown") {
    warnings.push("unknown_prompt_family");
  }

  if (
    safeString(visualModeRaw) &&
    safeString(visualModeRaw) !== visualModeNormalized
  ) {
    warnings.push("visual_mode_normalized_from_legacy_alias");
  }

  return warnings;
}

// ===============================
// MAIN
// ===============================

const items = $input.all();

return items.map((item, idx) => {
  const inputJson = item.json ?? {};
  const rawInput = inputJson.visualSegment ?? inputJson ?? {};

  const segmentAnalysis = rawInput.segment_analysis ?? {};
  const segmentMeta = rawInput.segment_meta ?? {};
  const segmentPlan = rawInput.segment_plan ?? {};
  const sourceFileName = inputJson.fileName ?? rawInput.fileName ?? "";

  const visualModeRaw =
    safeString(VISUAL_MODE) ||
    safeString(inputJson.visual_mode) ||
    safeString(inputJson.visualMode) ||
    safeString(rawInput.visual_mode) ||
    safeString(rawInput.visualMode);

  const visualMode = deriveVisualMode(VISUAL_MODE, inputJson, rawInput);

  const segmentIndex =
    Number.isInteger(segmentPlan.segment_index)
      ? segmentPlan.segment_index
      : Number.isInteger(segmentAnalysis.segment_index)
        ? segmentAnalysis.segment_index
        : Number.isInteger(segmentMeta.partIndex)
          ? segmentMeta.partIndex
          : idx;

  const selectedBaseFormat = safeString(segmentPlan.selected_base_format);
  const useExplanatoryLayer = safeBool(segmentPlan.use_explanatory_layer, false);

  const promptFamily = getPromptFamily(visualMode, selectedBaseFormat);
  const templateIds = getTemplateIds(promptFamily, visualMode, useExplanatoryLayer);
  const languagePolicy = getLanguagePolicy(promptFamily);
  const promptFamilyKind = getPromptFamilyKind(promptFamily);

  const startFrameTextMode = getStartFrameTextMode(
    promptFamilyKind,
    selectedBaseFormat
  );

  const allowStartFrameEmbeddedAnnotations =
    startFrameTextMode === "required";

  const requiresTextCapableStartFrameModel =
    startFrameTextMode === "required";

  const warnings = buildWarnings(
    selectedBaseFormat,
    promptFamily,
    visualModeRaw,
    visualMode
  );

  const requiresStartFrame = templateIds.starting_frame_template_id !== null;
  const requiresClipPrompt = templateIds.clip_template_id !== null;
  const requiresOverlayPrompt =
    useExplanatoryLayer && templateIds.overlay_template_id !== null;

  const useLegacySceneTemplates =
    promptFamily === "realistic_scene_i2v" ||
    promptFamily === "archival_realistic_scene" ||
    promptFamily === "illustrated_scene_i2v";

  const outputFileName = sourceFileName
    ? sourceFileName.replace(/_visualSegment\.json$/i, "_promptRoute.json")
    : `segment_${String(segmentIndex).padStart(5, "0")}_promptRoute.json`;

  return {
    json: {
      segment_prompt_route: {
        schema_version: "1.0",
        segment_index: segmentIndex,
        visual_mode: visualMode,

        selected_base_format: selectedBaseFormat,
        format_tier: safeString(segmentPlan.format_tier),
        use_explanatory_layer: useExplanatoryLayer,
        segment_role_in_flow: safeString(segmentPlan.segment_role_in_flow),

        prompt_family: promptFamily,
        prompt_family_kind: promptFamilyKind,
        use_legacy_scene_templates: useLegacySceneTemplates,

        template_ids: templateIds,

        language_policy: languagePolicy,

        allowed_prompt_elements: buildAllowedPromptElements(languagePolicy),
        forbidden_prompt_elements: buildForbiddenPromptElements(languagePolicy),

        generation_requirements: {
          requires_start_frame: requiresStartFrame,
          requires_clip_prompt: requiresClipPrompt,
          requires_overlay_prompt: requiresOverlayPrompt,
        },

        start_frame_text_mode: startFrameTextMode,
        allow_start_frame_embedded_annotations: allowStartFrameEmbeddedAnnotations,
        requires_text_capable_start_frame_model: requiresTextCapableStartFrameModel,

        global_inputs: {
          selected_cluster_plan: SELECTED_CLUSTER_PLAN,
          visual_narration_strategy: VISUAL_NARRATION_STRATEGY,
          global_visual_policy: GLOBAL_VISUAL_POLICY,
        },

        warnings,
      },

      fileName: outputFileName,
    }
  };
});
